/**
 * main.js — reads PORTFOLIO config and renders the entire page
 * Do NOT edit this file for content changes — edit config.js instead.
 */

document.addEventListener('DOMContentLoaded', () => {
  applyMeta();
  renderHero();
  renderAbout();
  renderSkills();
  renderProjects();
  renderSecurity();
  renderExperience();
  renderEducationCerts();
  renderContact();
  renderFooter();
  initCursor();
  initParticles();
  initTypewriter();
  initScrollReveal();
  initCounters();
  initNavScroll();
  initMagneticButtons();
});

/* ─── META ─── */
function applyMeta() {
  const m = PORTFOLIO.meta;
  document.title = m.title;
  setMeta('description', m.description);
  setMeta('keywords',    m.keywords);
  setMeta('author',      m.author);
  setOg('og:title',       m.title);
  setOg('og:description', m.description);
  if (m.ogImage) setOg('og:image', m.ogImage);
  if (m.favicon) {
    const link = document.createElement('link');
    link.rel = 'icon'; link.href = m.favicon;
    document.head.appendChild(link);
  }
}
function setMeta(name, content) {
  let el = document.querySelector(`meta[name="${name}"]`);
  if (!el) { el = document.createElement('meta'); el.name = name; document.head.appendChild(el); }
  el.content = content;
}
function setOg(prop, content) {
  let el = document.querySelector(`meta[property="${prop}"]`);
  if (!el) { el = document.createElement('meta'); el.setAttribute('property', prop); document.head.appendChild(el); }
  el.content = content;
}

/* ─── HERO ─── */
function renderHero() {
  const h = PORTFOLIO.hero;
  document.querySelector('.hero-tag').textContent  = h.tagline;
  const nameEl = document.querySelector('.hero-name');
  nameEl.textContent   = h.name;
  nameEl.dataset.text  = h.name;
  document.querySelector('.hero-desc').textContent = h.description;
  const cta = document.querySelector('.hero-cta');
  cta.innerHTML = `
    <a href="${h.ctaPrimary.href}"   class="btn-primary"  >${h.ctaPrimary.label}  <span style="margin-left:.4rem">→</span></a>
    <a href="${h.ctaSecondary.href}" class="btn-secondary">${h.ctaSecondary.label}</a>
  `;
}

/* ─── ABOUT ─── */
function renderAbout() {
  const a = PORTFOLIO.about;
  // Photo
  const wrap = document.querySelector('.about-photo-wrap');
  if (a.photo) {
    const img = document.createElement('img');
    img.src = a.photo; img.alt = PORTFOLIO.meta.author;
    img.onerror = () => { img.replaceWith(buildPhotoPlaceholder()); };
    wrap.prepend(img);
  } else {
    wrap.prepend(buildPhotoPlaceholder());
  }
  // Paragraphs
  const textDiv = document.querySelector('.about-paragraphs');
  textDiv.innerHTML = a.paragraphs.map(p => `<p>${p}</p>`).join('');
  // Stats
  const statsRow = document.querySelector('.stats-row');
  statsRow.innerHTML = a.stats.map(s => `
    <div class="stat-box" style="border-color:${s.color}20;">
      <div class="stat-num" style="color:${s.color}" data-count="${s.number}">0</div>
      <div class="stat-label">${s.label}</div>
    </div>
  `).join('');
}
function buildPhotoPlaceholder() {
  const d = document.createElement('div');
  d.className = 'photo-placeholder';
  d.innerHTML = `<span style="font-size:3.5rem;opacity:.25">🧑‍💻</span><span>[ PHOTO COMING SOON ]</span>`;
  return d;
}

/* ─── SKILLS ─── */
function renderSkills() {
  const grid = document.querySelector('.skills-grid');
  grid.innerHTML = PORTFOLIO.skills.map((cat, i) => `
    <div class="skill-category reveal" style="border-left-color:${cat.color};transition-delay:${i*0.07}s">
      <div class="skill-cat-title" style="color:${cat.color}">${cat.category}</div>
      <div class="skill-tags">
        ${cat.tags.map(t => `<span class="skill-tag">${t}</span>`).join('')}
      </div>
    </div>
  `).join('');
}

/* ─── PROJECTS ─── */
function renderProjects() {
  const gallery = document.querySelector('.projects-gallery');
  gallery.innerHTML = PORTFOLIO.projects.map((p, i) => `
    <div class="project-album reveal" style="transition-delay:${i*0.12}s">
      <!-- Project Header/Icon -->
      <div class="album-header" style="background: linear-gradient(135deg, ${p.color}15 0%, ${p.color}05 100%);">
        <div class="album-icon" style="color: ${p.color}; text-shadow: 0 0 20px ${p.color}50;">${p.icon}</div>
        <div class="album-badge" style="background: ${p.color}; color: ${p.color === 'var(--neon-green)' || p.color === 'var(--neon-blue)' ? '#050a0e' : '#050a0e'};">${p.type === 'hosted' ? 'LIVE 🌐' : 'GITHUB 💻'}</div>
      </div>
      
      <!-- Project Title & Number -->
      <div class="album-title">
        <span class="album-num" style="color: ${p.color};">${p.number}</span>
        <div class="album-name">${p.name}</div>
      </div>
      
      <!-- Project Description -->
      <div class="album-desc">${p.description}</div>
      
      <!-- Metadata Bloom - Tech Stack -->
      <div class="bloom-container">
        <div class="bloom-center" style="background: ${p.color}; box-shadow: 0 0 20px ${p.color}60;"></div>
        <div class="bloom-petals">
          ${p.tech.map((t, idx) => `
            <div class="bloom-petal" style="
              --angle: ${(360 / p.tech.length) * idx}deg;
              --color: ${p.color};
              transform: rotate(var(--angle)) translateY(-70px);
              animation-delay: ${idx * 0.08}s;
            ">
              <span class="petal-text" style="transform: rotate(calc(-1 * var(--angle)));">${t}</span>
            </div>
          `).join('')}
        </div>
      </div>
      
      <!-- Project Links -->
      <div class="album-links">
        ${p.links.map(l => `
          <a href="${l.href}" target="_blank" class="album-link" style="border-color: ${p.color}40; color: ${p.color};">
            ${l.label} <span class="link-arrow">↗</span>
          </a>
        `).join('')}
      </div>
    </div>
  `).join('');
  
  // Render hosted projects gallery
  renderHostedGallery();
}

/* ─── HOSTED PROJECTS GALLERY ─── */
function renderHostedGallery() {
  const hostedGallery = document.querySelector('.hosted-gallery');
  const hostedProjects = PORTFOLIO.projects.filter(p => p.type === 'hosted');
  
  if (hostedProjects.length === 0) {
    hostedGallery.innerHTML = '<p style="color: #7a9bb5; text-align: center;">No hosted projects available.</p>';
    return;
  }
  
  hostedGallery.innerHTML = hostedProjects.map((p, i) => `
    <div class="hosted-card reveal" style="transition-delay:${i*0.15}s">
      <div class="hosted-header" style="background: linear-gradient(135deg, ${p.color}15 0%, ${p.color}05 100%);">
        <div class="hosted-badge" style="background: ${p.color};">${p.name}</div>
      </div>
      <div class="hosted-frame-wrapper">
        <div class="hosted-frame-loader">
          <span style="color: ${p.color};">Loading ${p.name}...</span>
        </div>
        <iframe 
          class="hosted-frame" 
          src="${p.links[0].href}" 
          title="${p.name} - Live Demo"
          onload="this.parentElement.querySelector('.hosted-frame-loader').style.display='none';"
          loading="lazy">
        </iframe>
      </div>
      <div class="hosted-footer" style="border-top-color: ${p.color}40;">
        <p class="hosted-desc">${p.description}</p>
        <div class="hosted-tech">
          ${p.tech.slice(0, 4).map(t => `<span class="hosted-tech-tag">${t}</span>`).join('')}
          ${p.tech.length > 4 ? `<span class="hosted-tech-tag">+${p.tech.length - 4}</span>` : ''}
        </div>
        <a href="${p.links[0].href}" target="_blank" class="hosted-cta" style="color: ${p.color}; border-color: ${p.color}40;">
          Visit Live Site <span>↗</span>
        </a>
      </div>
    </div>
  `).join('');
}

/* ─── SECURITY ─── */
function renderSecurity() {
  const ps = PORTFOLIO.security.portswigger;
  const lc = PORTFOLIO.security.leetcode;

  document.querySelector('#ps-level').textContent       = ps.level;
  document.querySelector('#ps-apprentice').textContent  = `${ps.apprentice.done} / ${ps.apprentice.total}`;
  document.querySelector('#ps-practitioner').textContent= `${ps.practitioner.done} / ${ps.practitioner.total}`;
  document.querySelector('#ps-expert').textContent      = `${ps.expert.done} / ${ps.expert.total}`;
  document.querySelector('#ps-coverage').textContent    = `${ps.vulnCoverage}%`;
  document.querySelector('#ps-bar').style.width         = ps.vulnCoverage + '%';

  document.querySelector('#lc-easy').textContent    = lc.easy.done;
  document.querySelector('#lc-easy-t').textContent  = `Easy / ${lc.easy.total}`;
  document.querySelector('#lc-med').textContent     = lc.medium.done;
  document.querySelector('#lc-med-t').textContent   = `Med / ${lc.medium.total}`;
  document.querySelector('#lc-hard').textContent    = lc.hard.done;
  document.querySelector('#lc-hard-t').textContent  = `Hard / ${lc.hard.total}`;
  document.querySelector('#lc-total').textContent   = lc.total;
  document.querySelector('#lc-days').textContent    = lc.activeDays;
  document.querySelector('#lc-streak').textContent  = lc.maxStreak;
  document.querySelector('#lc-rank').textContent    = '#' + lc.rank;
  document.querySelector('#lc-lang').textContent    = lc.primaryLang;
  document.querySelector('#lc-link').href           = lc.profileUrl;
}

/* ─── EXPERIENCE ─── */
function renderExperience() {
  const tl = document.querySelector('.timeline');
  tl.innerHTML = PORTFOLIO.experience.map(e => `
    <div class="timeline-item">
      <div class="timeline-dot" style="background:${e.color};color:${e.color};${e.current ? 'animation:pulseGlow 2s infinite;' : ''}"></div>
      <div class="timeline-header">
        <div class="timeline-date">
          ${e.period}
          ${e.current ? '<span class="badge-current">● CURRENT</span>' : ''}
          ${e.location.includes('Freelance') ? '<span class="badge-freelancer">💼 FREELANCER</span>' : ''}
        </div>
        <div class="timeline-role">${e.role}</div>
        <div class="timeline-company" style="color:${e.color}">${e.company} · ${e.location}</div>
      </div>
      <ul class="timeline-bullets">
        ${e.bullets.map(b => `<li>${b}</li>`).join('')}
      </ul>
      ${e.skills.length ? `
        <div class="timeline-skills">
          ${e.skills.map(s => `<span class="timeline-skill">${s}</span>`).join('')}
        </div>` : ''}
    </div>
  `).join('');
}

