/* ─── CONTACT ─── */
function renderContact() {
  const c = PORTFOLIO.contact;
  const linksEl = document.querySelector('.contact-links');
  linksEl.innerHTML = c.links.map(l => `
    <a href="${l.href}" target="${l.href.startsWith('mailto') ? '_self' : '_blank'}" class="contact-link">
      <span>${l.icon}</span> ${l.label}
    </a>
  `).join('');
  
  // Initialize Formspree contact form
  initContactForm();
}

function initContactForm() {
  const form = document.getElementById('contact-form');
  const statusEl = document.getElementById('form-status');
  
  if (!form) return;
  
  form.addEventListener('submit', async (e) => {
    e.preventDefault();
    
    statusEl.textContent = '📤 Sending...';
    statusEl.className = '';
    
    try {
      const response = await fetch(form.action, {
        method: 'POST',
        body: new FormData(form),
        headers: {
          'Accept': 'application/json'
        }
      });
      
      if (response.ok) {
        statusEl.textContent = '✅ Message sent successfully! I\'ll get back to you soon.';
        statusEl.className = 'success';
        form.reset();
        setTimeout(() => {
          statusEl.textContent = '';
        }, 5000);
      } else {
        statusEl.textContent = '❌ Error sending message. Please try again.';
        statusEl.className = 'error';
      }
    } catch (error) {
      statusEl.textContent = '❌ Network error. Please check your connection and try again.';
      statusEl.className = 'error';
      console.error('Form submission error:', error);
    }
  });
}

/* ─── FOOTER ─── */
